// ── Assets ───────────────────────────────────────────────────────────────────

async function cmdAssets(rest) {
  const sub = rest[0];
  if (!sub) throw new Error('assets requires a subcommand: list | upload');
  const subRest = rest.slice(1);

  if (sub === 'list') {
    const f = parseArgs(subRest, { boolFlags: ['json'] });
    const docId = f._[0];
    if (!docId) throw new Error('assets list requires <doc-id>');
    const { api } = buildContext(f);
    const res = await api.listDocumentAssets(docId);
    if (f.json) return printJson(res);
    const list = res.data || res.assets || res || [];
    if (!list.length) { out('(no assets)'); return; }
    for (const a of list) {
      const name = a.filename || a.name || a;
      const size = a.size ? `  ${a.size}B` : '';
      out(`${name}${size}`);
    }
    return;
  }

  if (sub === 'upload') {
    const f = parseArgs(subRest, { boolFlags: ['json'] });
    const docId = f._[0];
    const files = f._.slice(1);
    if (!docId || !files.length) throw new Error('assets upload requires <doc-id> <file> [<file>...]');
    for (const fp of files) {
      if (!fs.existsSync(fp)) throw new Error(`file not found: ${fp}`);
    }
    const { api } = buildContext(f);
    const res = await api.uploadDocumentAssets(docId, files);
    if (f.json) return printJson(res);
    out(`uploaded ${files.length} asset${files.length === 1 ? '' : 's'} to doc ${docId}`);
    return;
  }

  throw new Error(`unknown assets subcommand: ${sub}`);
}

