// ── Admin (requires session JWT) ─────────────────────────────────────────────

async function getAdminJwt(flags) {
  const cfg = loadConfig({ envFile: flags['env-file'], profile: flags.profile });
  const baseUrl = normalizeBaseUrl(flags.url || cfg.baseUrl);
  let username = flags.username || cfg.savedUsername;
  let password = flags.password;
  if (cfg.profileName && !password) {
    const profile = profileMod.readProfile(cfg.profileName);
    if (profile && profile.password) password = profile.password;
  }
  if (!username) username = (await promptLine('Username: ')).trim();
  if (!password) password = await promptHidden('Password: ');
  const api = buildClient({ token: '__placeholder__', baseUrl });
  const res = await api.loginPassword(username, password);
  if (!res.token) throw new Error('login response missing token');
  return { jwt: res.token, baseUrl, username };
}

async function cmdAdmin(rest) {
  const sub = rest[0];
  const sub2 = rest[1];
  if (!sub) throw new Error('admin requires a subcommand: users | settings');
  const subRest = rest.slice(2);

  if (sub === 'users') {
    if (sub2 === 'list') {
      const f = parseArgs(subRest, { boolFlags: ['json'] });
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      const res = await api.listUsers(jwt);
      if (f.json) return printJson(res);
      const list = Array.isArray(res) ? res : (res.data || []);
      if (!list.length) { out('(no users)'); return; }
      for (const u of list) out(`${u.username.padEnd(24)}  ${u.role}  ${u.created_at || ''}`);
      return;
    }
    if (sub2 === 'add' || sub2 === 'create') {
      const f = parseArgs(subRest, { boolFlags: ['json'] });
      const name = f._[0];
      if (!name) throw new Error('admin users add requires <name>');
      let password = f['new-password'] || f.password;
      if (!password) password = await promptHidden(`Password for ${name}: `);
      const role = f.role || 'viewer';
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      const res = await api.createUser(jwt, { username: name, password, role });
      if (f.json) return printJson(res);
      out(`created ${res.username}  (${res.role})`);
      return;
    }
    if (sub2 === 'update') {
      const f = parseArgs(subRest, { boolFlags: ['json'] });
      const name = f._[0];
      if (!name) throw new Error('admin users update requires <name>');
      const body = {};
      if (f.role !== undefined) body.role = f.role;
      if (f['new-password']) body.password = f['new-password'];
      if (!Object.keys(body).length) throw new Error('nothing to update (pass --role and/or --new-password)');
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      const res = await api.updateUser(jwt, name, body);
      if (f.json) return printJson(res);
      out(`updated ${res.username}  (${res.role})`);
      return;
    }
    if (sub2 === 'rm' || sub2 === 'delete') {
      const f = parseArgs(subRest, { boolFlags: ['json', 'yes'], aliases: { y: 'yes' } });
      const name = f._[0];
      if (!name) throw new Error('admin users rm requires <name>');
      if (!f.yes && process.stdin.isTTY) {
        const ok = (await promptLine(`Delete user ${name}? (y/N) `)).trim().toLowerCase();
        if (ok !== 'y' && ok !== 'yes') { out('aborted'); return; }
      }
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      await api.deleteUser(jwt, name);
      out(`deleted ${name}`);
      return;
    }
    throw new Error(`unknown admin users subcommand: ${sub2}`);
  }

  if (sub === 'settings') {
    if (sub2 === 'get') {
      const f = parseArgs(subRest, { boolFlags: ['json'] });
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      const res = await api.getSettings(jwt);
      if (f.json) return printJson(res);
      for (const [k, v] of Object.entries(res)) out(`${k}: ${v}`);
      return;
    }
    if (sub2 === 'set') {
      const f = parseArgs(subRest, { boolFlags: ['json'] });
      const body = {};
      if (f.registration !== undefined) {
        const v = String(f.registration).toLowerCase();
        body.registration_enabled = (v === 'on' || v === 'true' || v === '1');
      }
      if (!Object.keys(body).length) throw new Error('nothing to set (pass --registration on|off)');
      const { jwt, baseUrl } = await getAdminJwt(f);
      const api = buildClient({ token: '__placeholder__', baseUrl });
      const res = await api.updateSettings(jwt, body);
      if (f.json) return printJson(res);
      for (const [k, v] of Object.entries(res)) out(`${k}: ${v}`);
      return;
    }
    throw new Error(`unknown admin settings subcommand: ${sub2}`);
  }

  throw new Error(`unknown admin subcommand: ${sub}`);
}

// ── whoami / login / logout / use / profiles ─────────────────────────────────

async function cmdWhoami(rest) {
  const f = parseArgs(rest, { boolFlags: ['json'] });
  const { cfg } = buildContext(f);
  const allProfiles = profileMod.listProfiles();
  const current = profileMod.getCurrent();

  // Optionally probe /auth/me to confirm identity (best-effort)
  // Only when the token actually authenticates — agent tokens use a different
  // header so /auth/me may return 401; that's fine, we skip silently.

  if (f.json) {
    return printJson({
      active_profile: current || null,
      profile_in_use: cfg.profileName || null,
      profile_source: cfg.profileSource,
      base_url: cfg.baseUrl,
      env_file: cfg.envFilePath || null,
      token_source: cfg.tokenSource,
      token_prefix: cfg.token ? cfg.token.slice(0, 8) + '…' : null,
      username: cfg.savedUsername || null,
      token_name: cfg.savedTokenName || null,
      profiles: allProfiles.map(name => {
        const p = profileMod.readProfile(name) || {};
        return {
          name,
          base_url: p.baseUrl || null,
          username: p.username || null,
          active: name === current
        };
      })
    });
  }

  out(`active:     ${current || '(none)'}`);
  if (cfg.profileName && cfg.profileName !== current) {
    out(`in use:     ${cfg.profileName} (via ${cfg.profileSource})`);
  }
  out(`base url:   ${cfg.baseUrl}`);
  out(`env file:   ${cfg.envFilePath || '(none found)'}`);
  out(`token src:  ${cfg.tokenSource || 'none'}`);
  out(`token:      ${cfg.token ? cfg.token.slice(0, 8) + '…' : '(not set)'}`);
  if (cfg.savedUsername) out(`username:   ${cfg.savedUsername}`);
  if (cfg.savedTokenName) out(`token name: ${cfg.savedTokenName}`);
  if (allProfiles.length) {
    out('profiles:');
    for (const name of allProfiles) {
      const p = profileMod.readProfile(name) || {};
      const tag = name === current ? '  (active)' : '';
      out(`  ${name.padEnd(16)}${(p.baseUrl || '').padEnd(40)}${tag}`);
    }
  } else {
    out('profiles:   (none — run `md_cli login` to create one)');
  }
}

function warnIfShadowed(cfgPre) {
  if (process.env.MD_BROWSE_TOKEN) {
    err(
      `\nwarning: MD_BROWSE_TOKEN is set in your shell environment — it takes priority\n`
      + `         over the saved token. Unset it (\`unset MD_BROWSE_TOKEN\`) or the\n`
      + `         saved token won't be used.`
    );
  } else if (cfgPre.tokenSource === 'env-file' && cfgPre.envFilePath) {
    err(
      `\nwarning: MD_BROWSE_TOKEN is set in ${cfgPre.envFilePath} — it takes priority\n`
      + `         over the saved token. Remove it from .env or the saved token\n`
      + `         won't be used. Run \`md_cli whoami\` to see which is active.`
    );
  }
}

const DEFAULT_TOKEN_SCOPES = [
  'documents:read', 'documents:write', 'versions:read', 'search:read', 'audit:read'
];

function resolveLoginProfile(flags, baseUrl) {
  const explicit = !!flags.profile;
  let name = flags.profile || profileMod.deriveName(baseUrl);
  profileMod.validateName(name);
  return { name, exists: profileMod.profileExists(name), explicit };
}

async function cmdLogin(rest) {
  const f = parseArgs(rest, { boolFlags: ['no-validate', 'no-switch', 'force', 'save-password'] });
  const cfgPre = loadConfig({ envFile: f['env-file'] });
  const baseUrl = normalizeBaseUrl(f.url || cfgPre.baseUrl);
  if (!baseUrl) throw new Error('login requires --url or MD_BROWSE_URL set in your environment');

  const { name: profileName, exists: profileExists, explicit: profileExplicit } =
    resolveLoginProfile(f, baseUrl);

  if (profileExists && !profileExplicit && !f.force) {
    throw new Error(
      `profile "${profileName}" already exists. ` +
      `Use --profile <new-name> to pick a different name, ` +
      `or --force to overwrite (the old token will no longer be remembered).`
    );
  }

  // Path 1: --token escape hatch.
  if (f.token) {
    const token = f.token;
    if (!f['no-validate']) {
      const api = buildClient({ token, baseUrl });
      try { await api.listDocuments({ page_size: 1 }); }
      catch (e) {
        const msg = e instanceof ApiError ? `${e.message} (HTTP ${e.status})` : (e.message || String(e));
        throw new Error(`token validation failed: ${msg}`);
      }
    }
    profileMod.writeProfile(profileName, {
      token, baseUrl, saved_at: new Date().toISOString()
    });
    if (!f['no-switch']) profileMod.setCurrent(profileName);
    out(`saved to  ${profileMod.profilePath(profileName)}`);
    out(`profile:  ${profileName}${f['no-switch'] ? '' : '  (active)'}`);
    out(`base url: ${baseUrl}`);
    out(`token:    ${token.slice(0, 8)}…`);
    warnIfShadowed(cfgPre);
    return;
  }

  // Path 2 (default): username/password → mint a long-lived agent token.
  let username = f.username || f.user;
  if (!username) username = (await promptLine('Username: ')).trim();
  if (!username) throw new Error('login requires a username');

  const password = f.password !== undefined ? f.password : await promptHidden('Password: ');
  if (!password) throw new Error('password is required');

  const api = buildClient({ token: '__placeholder__', baseUrl });
  let session;
  try {
    session = await api.loginPassword(username, password);
  } catch (e) {
    if (e instanceof ApiError) throw new Error(`login failed (HTTP ${e.status}): ${e.body?.error?.message || 'check username/password'}`);
    throw new Error(`could not reach ${baseUrl}/api/auth/login: ${e.message}`);
  }
  const jwt = session.token;
  if (!jwt) throw new Error('login response missing token');

  const tokenName = f.name || `md_cli@${os.hostname()} ${new Date().toISOString().slice(0, 16).replace('T', ' ')}`;
  const scopes = f.scopes
    ? String(f.scopes).split(',').map(s => s.trim()).filter(Boolean)
    : DEFAULT_TOKEN_SCOPES;

  let minted;
  try {
    minted = await api.mintAgentToken(jwt, { name: tokenName, scopes });
  } catch (e) {
    if (e instanceof ApiError) {
      throw new Error(`failed to mint token (HTTP ${e.status}): ${e.body?.error?.message || ''}`);
    }
    throw e;
  }
  const secretToken = minted.secret_token;
  if (!secretToken) throw new Error('token creation response missing secret_token');

  const state = {
    token: secretToken,
    baseUrl,
    username,
    token_name: tokenName,
    saved_at: new Date().toISOString()
  };
  if (f['save-password']) state.password = password;
  profileMod.writeProfile(profileName, state);
  if (!f['no-switch']) profileMod.setCurrent(profileName);
  out(`logged in as ${username}`);
  out(`saved to  ${profileMod.profilePath(profileName)}`);
  out(`profile:  ${profileName}${f['no-switch'] ? '' : '  (active)'}`);
  out(`base url: ${baseUrl}`);
  out(`token:    ${secretToken.slice(0, 8)}…  (name: ${tokenName})`);
  out(`scopes:   ${scopes.join(', ')}`);
  if (f['save-password']) out(`note:     password stored in profile (admin commands won't re-prompt)`);
  warnIfShadowed(cfgPre);
}

async function cmdLogout(rest) {
  const f = parseArgs(rest, { boolFlags: ['all'] });
  if (f.all) {
    const all = profileMod.listProfiles();
    if (!all.length) { out('no profiles to remove'); return; }
    for (const name of all) profileMod.deleteProfile(name);
    profileMod.clearCurrent();
    out(`removed ${all.length} profile${all.length === 1 ? '' : 's'}: ${all.join(', ')}`);
    return;
  }
  const target = f.profile || profileMod.getCurrent();
  if (!target) {
    out('no active profile to log out of. Use `md_cli profiles rm <name>` to delete a specific profile.');
    return;
  }
  const removed = profileMod.deleteProfile(target);
  if (target === profileMod.getCurrent()) profileMod.clearCurrent();
  out(removed ? `removed profile: ${target}` : `profile not found: ${target}`);
  if (removed && !profileMod.getCurrent()) {
    const remaining = profileMod.listProfiles();
    if (remaining.length) {
      profileMod.setCurrent(remaining[0]);
      out(`active profile is now: ${remaining[0]}`);
    }
  }
}

async function cmdUse(rest) {
  const f = parseArgs(rest);
  const name = f._[0];
  if (!name) throw new Error('use requires a profile name. Try `md_cli profiles` to list available profiles.');
  profileMod.validateName(name);
  if (!profileMod.profileExists(name)) {
    const all = profileMod.listProfiles();
    throw new Error(
      `no such profile: ${name}.${all.length ? ` Available: ${all.join(', ')}` : ' Run `md_cli login` first.'}`
    );
  }
  profileMod.setCurrent(name);
  const p = profileMod.readProfile(name) || {};
  out(`active profile: ${name}${p.baseUrl ? `  (${p.baseUrl})` : ''}`);
}

async function cmdProfiles(rest) {
  const sub = rest[0] && !rest[0].startsWith('-') ? rest[0] : 'list';
  const subRest = (sub === rest[0]) ? rest.slice(1) : rest;

  if (sub === 'list') {
    const f = parseArgs(subRest, { boolFlags: ['json'] });
    const all = profileMod.listProfiles();
    const current = profileMod.getCurrent();
    if (f.json) {
      return printJson({
        active: current || null,
        profiles: all.map(name => {
          const p = profileMod.readProfile(name) || {};
          return { name, base_url: p.baseUrl || null, username: p.username || null, active: name === current };
        })
      });
    }
    if (!all.length) { out('(no profiles — run `md_cli login` to create one)'); return; }
    for (const name of all) {
      const p = profileMod.readProfile(name) || {};
      const tag = name === current ? '  (active)' : '';
      out(`${name.padEnd(16)}${(p.baseUrl || '').padEnd(40)}${tag}`);
    }
    return;
  }

  if (sub === 'rm' || sub === 'delete' || sub === 'remove') {
    const f = parseArgs(subRest);
    const name = f._[0];
    if (!name) throw new Error('profiles rm requires a name');
    profileMod.validateName(name);
    if (!profileMod.profileExists(name)) throw new Error(`no such profile: ${name}`);
    profileMod.deleteProfile(name);
    if (profileMod.getCurrent() === name) profileMod.clearCurrent();
    out(`removed profile: ${name}`);
    return;
  }

  if (sub === 'rename' || sub === 'mv') {
    const f = parseArgs(subRest);
    const oldName = f._[0];
    const newName = f._[1];
    if (!oldName || !newName) throw new Error('profiles rename requires <old> <new>');
    profileMod.validateName(oldName);
    profileMod.validateName(newName);
    if (!profileMod.profileExists(oldName)) throw new Error(`no such profile: ${oldName}`);
    if (profileMod.profileExists(newName)) throw new Error(`profile already exists: ${newName}`);
    const data = profileMod.readProfile(oldName);
    profileMod.writeProfile(newName, data);
    profileMod.deleteProfile(oldName);
    if (profileMod.getCurrent() === oldName) profileMod.setCurrent(newName);
    out(`renamed ${oldName} → ${newName}`);
    return;
  }

  throw new Error(`unknown profiles subcommand: ${sub}\nrun \`md_cli help profiles\` for usage.`);
}

// ── Dispatch ─────────────────────────────────────────────────────────────────

const COMMANDS = {
  list: cmdList,
  ls: cmdList,
  search: cmdSearch,
  get: cmdGet,
  upload: cmdUpload,
  update: cmdUpdate,
  delete: cmdDelete,
  rm: cmdDelete,
  versions: cmdVersions,
  rollback: cmdRollback,
  chunks: cmdChunks,
  download: cmdDownload,
  'download-batch': cmdDownloadBatch,
  'batch-delete': cmdBatchDelete,
  'batch-move': cmdBatchMove,
  share: cmdShare,
  folders: cmdFolders,
  folder: cmdFolders,
  tokens: cmdTokens,
  audit: cmdAudit,
  'audit-logs': cmdAudit,
  categories: cmdCategories,
  tags: cmdTags,
  health: cmdHealth,
  ping: cmdHealth,
  assets: cmdAssets,
  'folder-assets': cmdFolderAssets,
  admin: cmdAdmin,
  login: cmdLogin,
  logout: cmdLogout,
  whoami: cmdWhoami,
  use: cmdUse,
  profiles: cmdProfiles,
  profile: cmdProfiles
};

// Global flags accepted before the command; lifted out and appended to the
// command's own argv so `md_cli --url X list` and `md_cli list --url X` behave
// identically.
const GLOBAL_VALUE_FLAGS = new Set(['--token', '--url', '--env-file', '--profile']);
const GLOBAL_BOOL_FLAGS = new Set(['--json']);

function liftGlobalFlags(argv) {
  const lifted = [];
  let i = 0;
  while (i < argv.length) {
    const a = argv[i];
    if (a === '--') break;
    if (GLOBAL_BOOL_FLAGS.has(a)) { lifted.push(a); i += 1; continue; }
    const eq = a.indexOf('=');
    const head = eq >= 0 ? a.slice(0, eq) : a;
    if (GLOBAL_VALUE_FLAGS.has(head)) {
      if (eq >= 0) { lifted.push(a); i += 1; }
      else { lifted.push(a, argv[i + 1]); i += 2; }
      continue;
    }
    break;
  }
  return { lifted, rest: argv.slice(i) };
}

async function run(rawArgv) {
  const { lifted, rest: argv } = liftGlobalFlags(rawArgv);

  if (!rawArgv.length) {
    out(HELP);
    out(ABOUT);
    return;
  }
  if (!argv.length || argv[0] === '-h' || argv[0] === '--help' || argv[0] === 'help') {
    if (argv[1] && COMMAND_HELP[argv[1]]) {
      out(COMMAND_HELP[argv[1]]);
    } else {
      out(HELP);
    }
    return;
  }
  if (argv[0] === '--version' || argv[0] === '-v' || argv[0] === 'version') {
    out(`md_cli ${VERSION}  ·  build ${BUILD}`);
    return;
  }

  const [cmd, ...subArgv] = argv;
  const rest = subArgv.concat(lifted);
  const handler = COMMANDS[cmd];
  if (!handler) {
    throw new Error(`unknown command: ${cmd}\nrun \`md_cli help\` for usage.`);
  }

  if (rest.includes('-h') || rest.includes('--help')) {
    out(COMMAND_HELP[cmd] || HELP);
    return;
  }

  try {
    await handler(rest);
  } catch (e) {
    if (e instanceof ApiError) {
      const reqId = e.requestId ? ` (request_id=${e.requestId})` : '';
      throw new Error(`${e.message}${reqId}`);
    }
    throw e;
  }
}

module.exports = { run };
